using System;
using System.Threading.Tasks;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

[TestClass]
public sealed class PaymentGatewayTests
{
    private readonly PaymentGateway _sut = new();

    // --- ChargeAsync ---

    [TestMethod]
    public async Task ChargeAsync_ValidTokenAndAmount_ReturnsSuccessResult()
    {
        var result = await _sut.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsNotNull(result);
        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    [DataRow("tok_visa", 0.01, DisplayName = "Minimum positive amount")]
    [DataRow("tok_mastercard", 9999.99, DisplayName = "Large amount")]
    [DataRow("tok_amex", 1.00, DisplayName = "Whole dollar amount")]
    public async Task ChargeAsync_VariousValidInputs_Succeeds(string token, double amount)
    {
        var result = await _sut.ChargeAsync(token, (decimal)amount);

        Assert.IsNotNull(result);
        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_NullToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _sut.ChargeAsync(null!, 10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_EmptyToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _sut.ChargeAsync(string.Empty, 10.00m));
    }

    [TestMethod]
    [DataRow(0.0, DisplayName = "Zero amount")]
    [DataRow(-5.0, DisplayName = "Negative amount")]
    public async Task ChargeAsync_InvalidAmount_ThrowsArgumentException(double amount)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _sut.ChargeAsync("tok_valid", (decimal)amount));
    }

    [TestMethod]
    public async Task ChargeAsync_ReturnsUniqueChargeIds()
    {
        var result1 = await _sut.ChargeAsync("tok_a", 10.00m);
        var result2 = await _sut.ChargeAsync("tok_b", 20.00m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }

    // --- RefundAsync ---

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccessResult()
    {
        // Arrange — charge first to get a valid chargeId
        var charge = await _sut.ChargeAsync("tok_refundable", 25.00m);

        // Act
        var refund = await _sut.RefundAsync(charge.ChargeId);

        // Assert
        Assert.IsNotNull(refund);
        Assert.IsTrue(refund.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(refund.RefundId));
    }

    [TestMethod]
    public async Task RefundAsync_NullChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _sut.RefundAsync(null!));
    }

    [TestMethod]
    public async Task RefundAsync_EmptyChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _sut.RefundAsync(string.Empty));
    }

    [TestMethod]
    public async Task RefundAsync_NonexistentChargeId_ReturnsFailure()
    {
        var result = await _sut.RefundAsync("ch_does_not_exist");

        Assert.IsFalse(result.Success);
    }

    // --- ChargeResult record ---

    [TestMethod]
    public void ChargeResult_Properties_AreAccessible()
    {
        var result = new ChargeResult("ch_123", true);

        Assert.AreEqual("ch_123", result.ChargeId);
        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public void ChargeResult_Equality_WorksByValue()
    {
        var a = new ChargeResult("ch_1", true);
        var b = new ChargeResult("ch_1", true);
        var c = new ChargeResult("ch_2", false);

        Assert.AreEqual(a, b);
        Assert.AreNotEqual(a, c);
    }

    // --- RefundResult record ---

    [TestMethod]
    public void RefundResult_Properties_AreAccessible()
    {
        var result = new RefundResult("re_456", false);

        Assert.AreEqual("re_456", result.RefundId);
        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public void RefundResult_Equality_WorksByValue()
    {
        var a = new RefundResult("re_1", true);
        var b = new RefundResult("re_1", true);
        var c = new RefundResult("re_1", false);

        Assert.AreEqual(a, b);
        Assert.AreNotEqual(a, c);
    }
}

